const body = $('Webhook').item.json.body;
const msgData = body.data;
const jid = msgData.key.remoteJid;
const msg = msgData.message || {};
const text = msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || msg.documentMessage?.caption || msg.videoMessage?.caption || '';
const timestamp = String(Date.now());
return { json: { jid, text, timestamp, instance: body.instance, redisKeyMsg: 'debounce_msg:' + jid, redisKeyTimer: 'debounce_timer:' + jid } };

// Consolida todos os itens vindos do Redis em um único texto
const allItems = $input.all();

// Coleta todos os textos de todos os itens
const textos = [];
for (const item of allItems) {
  const v = item.json.value;
  if (Array.isArray(v)) {
    textos.push(...v);
  } else if (typeof v === 'string' && v.trim()) {
    textos.push(v.trim());
  }
}

// Fallback: usa o texto direto do debounce se lista vazia
let unified = textos.join(' ').trim();
if (!unified) {
  unified = $('Debounce - Preparar').item.json.text || '';
}

unified = unified.replace(/\s+/g, ' ').trim();

// Retorna UM único item para o agente
return [{ json: { text: unified, jid: $('Debounce - Preparar').item.json.jid } }];

const output = $json.output || '';
let assunto = 'Geral';
let nomeAtendente = 'Equipe Solar Energy';
let numAtendente = '5567999501458'; // Táis - default

const lower = output.toLowerCase();
if (lower.includes('comercial') || lower.includes('venda') || lower.includes('proposta') || lower.includes('contrato') || lower.includes('orçamento') || lower.includes('projeto') || lower.includes('dimensionamento')) {
  assunto = 'Comercial';
  nomeAtendente = 'Rebecca';
  numAtendente = '5567996905913';
} else if (lower.includes('financeiro') || lower.includes('fatura') || lower.includes('boleto') || lower.includes('pagamento') || lower.includes('crédito') || lower.includes('débito') || lower.includes('cobrança') || lower.includes('conta alta') || lower.includes('refaturamento')) {
  assunto = 'Financeiro';
  nomeAtendente = 'Silvana';
  numAtendente = '5598988623937';
} else if (lower.includes('técnico') || lower.includes('inversor') || lower.includes('manutenção') || lower.includes('falha') || lower.includes('erro') || lower.includes('campo') || lower.includes('instalação') || lower.includes('painel') || lower.includes('placa') || lower.includes('defeito') || lower.includes('quebr') || lower.includes('suj') || lower.includes('geração baixa') || lower.includes('gerando pouco')) {
  assunto = 'Técnico';
  nomeAtendente = 'Marlos';
  numAtendente = '5567981261995';
} else {
  // Fallback geral: Táis
  nomeAtendente = 'Taís';
  numAtendente = '5567999501458';
}

const jid = $('Webhook').item.json.body.data.key.remoteJid;
const nomeCliente = $('Webhook').item.json.body.data.pushName || jid;
const motivoMatch = output.match(/\[ESCALAR_HUMANO\]\s*Motivo:\s*(.+)/);
const motivo = motivoMatch ? motivoMatch[1].trim() : assunto + ' - ' + nomeCliente;

return { json: { assunto, nomeAtendente, numAtendente, jid, nomeCliente, motivo } };

// Captura a string base64 do campo data
const b = $json.data.base64;

// Retorna no formato padrão do n8n: json + binary
return {
  json: { 
    processado: true,
    tamanho: b.length 
  },
  binary: {
    data: {
      data: Buffer.from(b, 'base64').toString('base64'),
      fileName: 'audio.ogg',
      mimeType: 'audio/ogg'
    }
  }
};

let items = $input.all();
items.forEach((item) => {
  let mime = item.json.mimetype || item.json.mime_type || 'application/octet-stream';
  if (['text/calendar','application/ics','text/x-calendar'].includes(mime)) item.json.mime_type_mapped = 'mapped/calendar';
  else if (['application/xml','text/xml'].includes(mime)) item.json.mime_type_mapped = 'mapped/xml';
  else item.json.mime_type_mapped = 'mapped/generic';
  item.json.original_mime = mime;
});
return items;

const b = $input.item.json.data.base64;
const bin = Buffer.from(b,'base64');
return [{ json:{}, binary:{ data:{ data:bin.toString('base64'), fileName:'arquivo.txt', mimeType:'text/plain' } } }];

// 1. Captura a string base64 que está dentro de data.base64
const b = $input.item.json.data.base64;

// 2. Captura o mimetype original (ex: image/jpeg)
const mime = $input.item.json.data.mimetype;

// 3. Captura o nome do arquivo original
const name = $input.item.json.data.fileName;

return {
  json: { 
    processado: true,
    tipo: "imagem",
    tamanho: $input.item.json.data.size.fileLength.low
  },
  binary: {
    data: {
      // Converte o base64 para o formato binário do n8n
      data: Buffer.from(b, 'base64').toString('base64'),
      fileName: name || 'imagem.jpg',
      mimeType: mime || 'image/jpeg'
    }
  }
};

// Filtra mensagens de grupos não cadastrados na base.
// DMs (@s.whatsapp.net) passam sempre.
// Grupos (@g.us) só passam se houver cliente vinculado em crm_clientes.us_grupo_whatsapp.
//
// Em caso de erro no lookup: bloqueia o grupo por segurança (fail-closed para grupos),
// e libera DMs (fail-open para DMs, já passariam direto).

const SUPABASE_URL = 'https://lodgnyduaezlcjxfcxrh.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImxvZGdueWR1YWV6bGNqeGZjeHJoIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc1NTM5MzY4NywiZXhwIjoyMDcwOTY5Njg3fQ.lKFf0-GmzUk1Dng6nw2hQQW3bkFmQ1EctFZ_I33nFx8';

const item = $input.first();
const body = item?.json?.body || {};
const jid  = body?.data?.key?.remoteJid || '';

// 1. DM: sempre passa
if (!jid.endsWith('@g.us')) {
  return [item];
}

// 2. Grupo: consulta lookup
try {
  const r = await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/rpc/buscar_cliente_por_whatsapp_jid`,
    headers: {
      Authorization: `Bearer ${SUPABASE_KEY}`,
      apikey: SUPABASE_KEY,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({ p_jid: jid }),
  });
  const out = typeof r === 'string' ? JSON.parse(r) : r;

  if (out && out.cliente_id) {
    // Grupo cadastrado: deixa passar
    return [item];
  }

  // Grupo não cadastrado: bloqueia silenciosamente
  console.log(`[Filtrar Grupos] Grupo bloqueado (não cadastrado): ${jid}`);
  return [];
} catch (e) {
  // Erro no lookup: bloqueia grupo por segurança
  console.log(`[Filtrar Grupos] Erro no lookup do grupo ${jid}, bloqueando: ${e?.message || e}`);
  return [];
}

